import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/product_model.dart'; import '../../../../services/api_service.dart'; import '../../../../services/local_storage_service.dart';
final productProvider = StateNotifierProvider<ProductNotifier, ProductState>((ref)=>ProductNotifier(ref));
class ProductState { final List<Product> products; final bool isLoading, hasMore; final int page; final String? search, category; ProductState({this.products=const[], this.isLoading=false, this.hasMore=true, this.page=0, this.search, this.category}); ProductState copyWith({List<Product>? products, bool? isLoading, bool? hasMore, int? page, String? search, String? category}) => ProductState(products: products??this.products, isLoading: isLoading??this.isLoading, hasMore: hasMore??this.hasMore, page: page??this.page, search: search, category: category); }
class ProductNotifier extends StateNotifier<ProductState> { final Ref ref; ProductNotifier(this.ref) : super(ProductState()); Future<void> load({bool refresh=false}) async { if(state.isLoading) return; if(!refresh && !state.hasMore) return; state = state.copyWith(isLoading:true); final api = ref.read(apiServiceProvider); final newPage = refresh?1:state.page+1; final newProds = await api.fetchProducts(page: newPage, pageSize:20, search: state.search, category: state.category); final all = refresh? newProds : [...state.products, ...newProds]; if(refresh) await LocalStorageService.saveProducts(all); state = state.copyWith(products: all, isLoading:false, hasMore: newProds.length==20, page: newPage); } void setSearch(String q) { state = state.copyWith(search: q.isEmpty?null:q, page:0, hasMore:true); load(refresh:true); } }
